const staticData = $getWorkflowStaticData('global');
const webhookData = $('Chat Token Webhook').first().json;

// ── Client config table ────────────────────────────────────
const CLIENTS = {
  digishares: { key: '__CLIENT_KEY_DIGISHARES__' },
  alkoholcz:  { key: '__CLIENT_KEY_ALKOHOLCZ__' },
};

const clientId = webhookData.body?.client_id || 'digishares';
const clientConfig = CLIENTS[clientId];

if (!clientConfig) {
  return [{ json: { valid: false, error: 'Unknown client' } }];
}

const clientKey = webhookData.body?.client_key || '';
if (clientConfig.key && clientKey !== clientConfig.key) {
  return [{ json: { valid: false, error: 'Invalid client key' } }];
}

// ── Rate limiting by IP ────────────────────────────────────
const MAX_CONVERSATIONS = 10;
const WINDOW_MS = 60 * 60 * 1000;

const forwarded = webhookData.headers?.['x-forwarded-for'] || '';
const ip = forwarded.split(',')[0].trim()
         || webhookData.headers?.['x-real-ip']
         || 'unknown';
const now = Date.now();

if (!staticData.rateLimits) staticData.rateLimits = {};

for (const key of Object.keys(staticData.rateLimits)) {
  if (now - staticData.rateLimits[key].firstRequest > WINDOW_MS) {
    delete staticData.rateLimits[key];
  }
}

const isRefresh = webhookData.body?.refresh === true;
const existingConversationSid = webhookData.body?.conversation_sid || '';

if (!isRefresh) {
  const entry = staticData.rateLimits[ip] || { count: 0, firstRequest: now };
  entry.count++;
  if (entry.count === 1) entry.firstRequest = now;
  staticData.rateLimits[ip] = entry;

  if (entry.count > MAX_CONVERSATIONS) {
    return [{ json: { valid: false, error: 'Too many requests. Try again later.' } }];
  }
}

return [{ json: { valid: true, isRefresh, existingConversationSid, clientId } }];

const ACCOUNT_SID    = '__ACCOUNT_SID__';
const API_KEY_SID    = '__API_KEY_SID__';
const SERVICE_SID    = '__SERVICE_SID__';
const TOKEN_TTL      = 1800;

const identity = $('Chat Token Webhook').first().json.body.identity;

const webhookBody = $('Chat Token Webhook').first().json.body;
let conversationSid;
if (webhookBody.refresh && webhookBody.conversation_sid) {
  conversationSid = webhookBody.conversation_sid;
} else {
  conversationSid = $('Create Conversation').first().json.sid;
}

function base64url(str) {
  return btoa(str).replace(/\\+/g, '-').replace(/\\//g, '_').replace(/=+$/g, '');
}

const now = Math.floor(Date.now() / 1000);

const header = JSON.stringify({ typ: 'JWT', alg: 'HS256', cty: 'twilio-fpa;v=1' });
const payload = JSON.stringify({
  jti: `${API_KEY_SID}-${now}`,
  iss: API_KEY_SID,
  sub: ACCOUNT_SID,
  iat: now,
  exp: now + TOKEN_TTL,
  grants: {
    identity: identity,
    chat: { service_sid: SERVICE_SID },
  },
});

const headerB64 = base64url(header);
const payloadB64 = base64url(payload);
const unsignedToken = `${headerB64}.${payloadB64}`;

return [{
  json: { unsignedToken, conversationSid },
}];

const unsignedToken = $('Prepare JWT').first().json.unsignedToken;
const conversationSid = $('Prepare JWT').first().json.conversationSid;
const hmacBase64 = $json.data;

const sig = hmacBase64.replace(/\\+/g, '-').replace(/\\//g, '_').replace(/=+$/g, '');

const token = `${unsignedToken}.${sig}`;

return [{
  json: { token, conversation_sid: conversationSid, region: 'ie1' },
}];
